const profile = p.profile || {};
const vwcFcRef = Number(p.vwcFcRef ?? p.field_capacity_estimate ?? p.field_capacity ?? 0);
const vwcFcRefSource = String(p.vwcFcRefSource || 'missing');
const drybackTarget = Number(p.drybackTarget ?? p.dryback_target ?? profile.dryback ?? 40);
const drybackMin = Number(p.drybackMin ?? p.dryback_target_min ?? Math.max(0, drybackTarget - 4));
const drybackMax = Number(p.drybackMax ?? p.dryback_target_max ?? Math.min(100, drybackTarget + 4));
const vwcFloorPct = Number(p.profile_vwc_floor_pct ?? profile.vwcFloorPct ?? 0);
const shotSizeBase = Number(p.shot_size_ml || profile.shot || 100);
const dripperCount = Number(p.dripper_count || 8);
const dripperFlow = Number(p.dripper_flowrate || 0.556);
const maxPump = Number(p.max_pump || 60);
const minGap = Number(p.min_gap || 30);
const maxIrrPerDay = Number(p.max_irrigations_per_day || profile.maxDay || 4);
const irrCountToday = Number(p.irrigation_count_today || 0);
const timeoutMin = Number(p.timeout || 15);
const sanityVwcMin = Number(p.sanity_vwc_min || 10);
const sanityVwcMax = Number(p.sanity_vwc_max || 90);
const sanityEcMin = Number(p.sanity_ec_min || 500);
const sanityEcMax = Number(p.sanity_ec_max || 6000);
const mode = String(p.control_mode || 'auto');
const primary = String(p.primary_control || 'dryback_first');
const fallback = String(p.fallback_mode || 'timed_survival');
const dryRun = !!p.dry_run_mode;
const manualOverride = !!p.manual_override_enabled;
const phaseAuto = !!p.phase_auto_mode;
const phaseMode = String(p.phase_mode || 'dryback_first');
const growthStage = String(p.growth_stage || 'p1');
const lastIrr = Number(p.last_irrigation_ms || 0);
const stateAgeMin = p.vwc_state_age_min != null ? Number(p.vwc_state_age_min) : null;
const fallbackShotsTodayLimit = Number(p.fallback_shots_limit || 2);
const fallbackTime = Number(p.fallback_time || 10);
const fallbackCountToday = Number(p.fallback_shots_today || 0);

const reasons = [];
let action = 'block';
let shotSize = shotSizeBase;
let pumpTime = 0;
let drybackPct = Number.isFinite(vwcFcRef) && vwcFcRef > 0 && Number.isFinite(vwc) ? ((vwcFcRef - vwc) / vwcFcRef) * 100 : null;
let fallbackCountOut = fallbackCountToday;
let irrCountOut = irrCountToday;

if (stateAgeMin !== null && stateAgeMin > timeoutMin) reasons.push('sensor_timeout');
if (!Number.isFinite(vwc) || !Number.isFinite(ec)) reasons.push('sensor_missing');
if (Number.isFinite(vwc) && (vwc < sanityVwcMin || vwc > sanityVwcMax)) reasons.push('vwc_out_of_range');
if (Number.isFinite(ec) && (ec < sanityEcMin || ec > sanityEcMax)) reasons.push('ec_out_of_range');
if (lastIrr && (now - lastIrr) < minGap * 60000) reasons.push('cooldown_active');
if (irrCountOut >= maxIrrPerDay) reasons.push('daily_limit_reached');
if (p.skip_next_shot) reasons.push('skip_next');
if (!(Number.isFinite(vwcFcRef) && vwcFcRef > 0)) reasons.push('vwcFcRef_missing');

const targetVwc = (Number.isFinite(vwcFcRef) && vwcFcRef > 0) ? (vwcFcRef * (1 - drybackTarget / 100)) : null;
const targetVwcMin = (Number.isFinite(vwcFcRef) && vwcFcRef > 0) ? (vwcFcRef * (1 - drybackMax / 100)) : null;
const targetVwcMax = (Number.isFinite(vwcFcRef) && vwcFcRef > 0) ? (vwcFcRef * (1 - drybackMin / 100)) : null;
const vwcFloorAbs = (Number.isFinite(vwcFcRef) && vwcFcRef > 0 && Number.isFinite(vwcFloorPct) && vwcFloorPct > 0) ? (vwcFcRef * (vwcFloorPct / 100)) : null;
const withinSteeringBand = Number.isFinite(drybackPct) && drybackPct >= drybackMin && drybackPct <= drybackMax;
const floorOK = vwcFloorAbs == null ? true : (Number.isFinite(vwc) && vwc >= vwcFloorAbs);
const drybackTrigger = Number.isFinite(drybackPct) && drybackPct >= 30;
const drybackStarted = Number.isFinite(drybackPct) && drybackPct >= drybackMin;
const waterOK = primary === 'dryback_first' ? (drybackStarted && floorOK) : true;
const canUseMainLogic = reasons.length === 0;

function computeShot() {
    const intentFactor = intent <= 3 ? 1.2 : intent <= 6 ? 1.0 : intent <= 8 ? 0.8 : 0.6;
    shotSize = Math.round(shotSizeBase * intentFactor);
    pumpTime = Math.min(Math.ceil(shotSize / (dripperCount * dripperFlow)), maxPump);
}
computeShot();

if (mode === 'manual') {
    action = 'manual';
} else if (canUseMainLogic && (mode === 'assist' || waterOK || drybackTrigger)) {
    action = 'auto_water';
} else if (reasons.length) {
    if (fallback === 'timed_survival' && fallbackCountOut < fallbackShotsTodayLimit) {
        action = 'fallback_water';
        pumpTime = Math.min(fallbackTime, maxPump);
        shotSize = Math.round(pumpTime * dripperCount * dripperFlow);
        fallbackCountOut += 1;
    } else {
        action = 'block';
        if (!reasons.includes('fallback_limit_reached') && !reasons.includes('fallback_disabled')) {
            reasons.push(fallbackCountOut >= fallbackShotsTodayLimit ? 'fallback_limit_reached' : 'fallback_disabled');
        }
