// Parses HH:MM[:SS] helper strings from msg properties into minutes.
function toMin(v){
  if(v == null) return null;
  const s = String(v).trim();
  if(!s) return null;
  const parts = s.split(':').map(Number);
  if(parts.some(n => Number.isNaN(n))) return null;
  const h = parts[0] || 0;
  const m = parts[1] || 0;
  const sec = parts[2] || 0;
  return h * 60 + m + (sec >= 30 ? 1 : 0);
}

msg.phaseData = {
  windows: {
    p0: { start: toMin(msg.phase_p0_start), end: toMin(msg.phase_p0_end) },
    p1: { start: toMin(msg.phase_p1_start), end: toMin(msg.phase_p1_end) },
    p2: { start: toMin(msg.phase_p2_start), end: toMin(msg.phase_p2_end) }
  },
  meta: {
    p0: `${msg.phase_p0_start || ''}-${msg.phase_p0_end || ''}`,
    p1: `${msg.phase_p1_start || ''}-${msg.phase_p1_end || ''}`,
    p2: `${msg.phase_p2_start || ''}-${msg.phase_p2_end || ''}`
  }
};

return msg;

// Calculates nowMinutes and activePhase while preserving the rest of msg.
function inWindow(now, start, end) {
  if (start == null || end == null) return false;
  if (start === end) return false;
  if (start < end) return now >= start && now < end;
  return now >= start || now < end;
}

const now = new Date();
const nowMin = now.getHours() * 60 + now.getMinutes();
const w = (msg.phaseData && msg.phaseData.windows) || {};
const meta = (msg.phaseData && msg.phaseData.meta) || {};

let activePhase = 'none';
let phaseInWindow = false;

if (inWindow(nowMin, w.p0?.start, w.p0?.end)) { activePhase = 'p0'; phaseInWindow = true; }
else if (inWindow(nowMin, w.p1?.start, w.p1?.end)) { activePhase = 'p1'; phaseInWindow = true; }
else if (inWindow(nowMin, w.p2?.start, w.p2?.end)) { activePhase = 'p2'; phaseInWindow = true; }

msg.phaseData = {
  windows: w,
  meta,
  nowMinutes: nowMin,
  activePhase,
  phaseInWindow,
  phaseEvalAt: now.toISOString()
};

msg.activePhase = activePhase;
msg.phaseInWindow = phaseInWindow;
msg.nowMinutes = nowMin;

return msg;

// CHADD PXPICS decision Core v5
// Based on core_v4_simple, with phaseData integration and EC no longer used as a blocker.
// Expected inputs:
// - msg.payload with sensor and config values
// - msg.phaseData from the phase window flow
// Output:
// - msg.payload with decision and calculated fields

const p = msg.payload || {};
const phase = msg.phaseData || {};
const now = Date.now();

const vwc = Number(p.vwc);
const ec = Number(p.ec);
const intent = Number(p.intent || 1);
const profile = p.profile || {};

const vwcFcRef = Number(p.vwcFcRef ?? p.field_capacity_estimate ?? p.field_capacity ?? 0);
const vwcFcRefSource = String(p.vwcFcRefSource || 'missing');
const drybackTarget = Number(p.drybackTarget ?? p.dryback_target ?? profile.dryback ?? 40);
const drybackMin = Number(p.drybackMin ?? p.dryback_target_min ?? Math.max(0, drybackTarget - 4));
const drybackMax = Number(p.drybackMax ?? p.dryback_target_max ?? Math.min(100, drybackTarget + 4));
const vwcFloorPct = Number(p.profile_vwc_floor_pct ?? profile.vwcFloorPct ?? 0);

const shotSizeBase = Number(p.shot_size_ml || profile.shot || 100);
const dripperCount = Number(p.dripper_count || 8);
const dripperFlow = Number(p.dripper_flowrate || 0.556);
const maxPump = Number(p.max_pump || 60);
const minGap = Number(p.min_gap || 30);

const maxIrrPerDay = Number(p.max_irrigations_per_day || profile.maxDay || 4);
const irrCountToday = Number(p.irrigation_count_today || 0);

const timeoutMin = Number(p.timeout || 15);
const sanityVwcMin = Number(p.sanity_vwc_min || 10);
const sanityVwcMax = Number(p.sanity_vwc_max || 90);

const fallbackShotsTodayLimit = Number(p.fallback_shots_limit || 2);
const fallbackTime = Number(p.fallback_time || 10);
const fallbackCountToday = Number(p.fallback_shots_today || 0);

const mode = String(p.control_mode || 'auto');
const primary = String(p.primary_control || 'dryback_first');
const fallback = String(p.fallback_mode || 'timed_survival');
const dryRun = !!p.dry_run_mode;
const manualOverride = !!p.manual_override_enabled;
const phaseAuto = !!p.phase_auto_mode;
const phaseMode = String(p.phase_mode || 'p0');
const growthStage = String(p.growth_stage || 'p1');

const lastIrr = Number(p.last_irrigation_ms || 0);
const stateAgeMin = p.vwc_state_age_min != null ? Number(p.vwc_state_age_min) : null;

const phaseActive = !!phase.activePhase && phase.activePhase !== 'none';
const activePhase = phaseAuto ? String(phase.activePhase || 'none') : phaseMode;
const phaseInWindow = !!phase.phaseInWindow;

const reasons = [];
let action = 'block';
let shotSize = shotSizeBase;
let pumpTime = 0;
let drybackPct = null;
let fallbackCountOut = fallbackCountToday;
let irrCountOut = irrCountToday;

// Hard blockers: only the critical sensor and timing conditions remain here.
if (stateAgeMin !== null && stateAgeMin > timeoutMin) reasons.push('sensor_timeout');
if (!Number.isFinite(vwc)) reasons.push('sensor_missing');
if (Number.isFinite(vwc) && (vwc < sanityVwcMin || vwc > sanityVwcMax)) reasons.push('vwc_out_of_range');
if (lastIrr && (now - lastIrr) < minGap * 60000) reasons.push('cooldown_active');
if (irrCountOut >= maxIrrPerDay) reasons.push('daily_limit_reached');
if (p.skip_next_shot) reasons.push('skip_next');
if (!(Number.isFinite(vwcFcRef) && vwcFcRef > 0)) reasons.push('vwcFcRef_missing');

// Dryback calculation against field capacity reference.
if (Number.isFinite(vwc) && Number.isFinite(vwcFcRef) && vwcFcRef > 0) {
    drybackPct = ((vwcFcRef - vwc) / vwcFcRef) * 100;
}

const targetVwc = (Number.isFinite(vwcFcRef) && vwcFcRef > 0)
    ? (vwcFcRef * (1 - drybackTarget / 100))
    : null;
const targetVwcMin = (Number.isFinite(vwcFcRef) && vwcFcRef > 0)
    ? (vwcFcRef * (1 - drybackMax / 100))
    : null;
const targetVwcMax = (Number.isFinite(vwcFcRef) && vwcFcRef > 0)
    ? (vwcFcRef * (1 - drybackMin / 100))
    : null;
const vwcFloorAbs = (Number.isFinite(vwcFcRef) && vwcFcRef > 0 && Number.isFinite(vwcFloorPct) && vwcFloorPct > 0)
    ? (vwcFcRef * (vwcFloorPct / 100))
    : null;

const withinSteeringBand = Number.isFinite(drybackPct)
    && drybackPct >= drybackMin
    && drybackPct <= drybackMax;

const floorOK = vwcFloorAbs == null
    ? true
    : (Number.isFinite(vwc) && vwc >= vwcFloorAbs);

const canUseMainLogic = reasons.length === 0;
const drybackTrigger = Number.isFinite(drybackPct) && drybackPct >= drybackTarget;
const drybackStarted = Number.isFinite(drybackPct) && drybackPct >= drybackMin;
const waterOK = primary === 'dryback_first'
    ? (drybackStarted && floorOK)
    : true;

function computeShot() {
    // Keep the same intent scaling pattern as v4.
    const intentFactor = intent <= 3 ? 1.2 : intent <= 6 ? 1.0 : intent <= 8 ? 0.8 : 0.6;
    shotSize = Math.round(shotSizeBase * intentFactor);
    pumpTime = Math.min(Math.ceil(shotSize / (dripperCount * dripperFlow)), maxPump);
}

computeShot();

// Decision order:
// 1) Manual mode wins.
// 2) Dry run logs the decision but should not be used to trigger a real pump downstream.
// 3) If phase_auto_mode is enabled, activePhase comes from phaseData.
//    If disabled, activePhase is taken from phase_mode.
// 4) Main watering logic only runs if critical blockers are clear.
// 5) Fallback can rescue blocked conditions if enabled.
if (mode === 'manual') {
    action = 'manual';
} else if (dryRun) {
    action = 'dry_run';
} else {
    // Optional phase-aware behavior.
    // When phase auto is enabled, phaseActive tells us whether we are currently inside a configured window.
    // When phase auto is off, the manually selected phaseMode becomes the active phase.
    if (canUseMainLogic) {
        if (phaseAuto) {
            if (phaseActive) {
                // In auto phase mode, phase is considered active only inside the configured time window.
                // This does not block EC anymore; EC is only carried through for visibility.
                if (Number.isFinite(vwcFcRef) && Number.isFinite(vwc) && vwc >= vwcFcRef) {
                    action = 'hold';
                    reasons.push('fc_reached');
                } else if (lastIrr && (now - lastIrr) < minGap * 60000) {
                    action = 'hold';
                    reasons.push('phase_cooldown');
                } else if (drybackStarted || drybackTrigger || mode === 'assist') {
                    action = 'auto_water';
                } else {
                    action = 'hold';
                    reasons.push('phase_wait');
                }
            } else {
                action = 'hold';
                reasons.push('outside_phase_window');
            }
        } else {
            // Manual phase selection: phase_mode is used as the active phase reference.
            if (Number.isFinite(vwcFcRef) && Number.isFinite(vwc) && vwc >= vwcFcRef) {
                action = 'hold';
                reasons.push('fc_reached');
            } else if (lastIrr && (now - lastIrr) < minGap * 60000) {
                action = 'hold';
                reasons.push('phase_cooldown');
            } else if (drybackStarted || drybackTrigger || mode === 'assist') {
                action = 'auto_water';
            } else {
                action = 'hold';
                reasons.push('manual_phase_wait');
            }
        }
    } else {
        // If hard blockers are present, allow fallback if configured.
        if (fallback === 'timed_survival' && fallbackCountOut < fallbackShotsTodayLimit) {
            action = 'fallback_water';
            pumpTime = Math.min(fallbackTime, maxPump);
            shotSize = Math.round(pumpTime * dripperCount * dripperFlow);
            fallbackCountOut += 1;
        } else {
            action = 'block';
            reasons.push(fallbackCountOut >= fallbackShotsTodayLimit ? 'fallback_limit_reached' : 'fallback_disabled');
        }
    }
}

// Preserve a running phase state in context for future phase logic.
const phaseState = context.get('phaseState') || {
    active: false,
    startedAt: 0,
    stage: 'idle',
    shotsSent: 0,
    targetFcReached: false,
    lastShotAt: 0
};

if (action === 'auto_water') {
    if (!phaseState.active) {
        phaseState.active = true;
        phaseState.startedAt = now;
        phaseState.stage = 'start';
        phaseState.shotsSent = 0;
        phaseState.targetFcReached = false;
    }
    phaseState.stage = 'shot_phase';
    phaseState.shotsSent += 1;
    phaseState.lastShotAt = now;
} else if (action === 'hold' && Number.isFinite(vwcFcRef) && Number.isFinite(vwc) && vwc >= vwcFcRef) {
    phaseState.active = false;
    phaseState.stage = 'fc_reached';
    phaseState.targetFcReached = true;
    phaseState.lastShotAt = now;
}

context.set('phaseState', phaseState);

const topicBase = String(p.mqtt_base || 'grow/CHADD_PXPICS').replace(/\/$/, '');
const zone = String(p.zone_name || 'zone_1');

msg.payload = {
    action,
    reasons: reasons.join(','),
    mode,
    primary,
    fallback,
    dryRun,
    manualOverride,
    phaseAuto,
    phaseMode,
    activePhase,
    phaseInWindow,
    growthStage,
    phaseState,
    vwc,
    ec,
    vwcFcRef,
    vwcFcRefSource,
    drybackPct,
    drybackTarget,
    drybackMin,
    drybackMax,
    targetVwc,
    targetVwcMin,
    targetVwcMax,
    vwcFloorPct,
    vwcFloorAbs,
    withinSteeringBand,
    floorOK,
    intent,
    shotSize,
    pumpTime,
    maxPump,
    now,
    lastIrr,
    fallbackCountToday: fallbackCountOut,
    fallbackShotsTodayLimit,
    irrCountToday: irrCountOut,
    maxIrrPerDay,
    topicBase,
    zone,
    profileName: p.profile_name,
    profile: p.profile
};

return msg;

const p = msg.payload || {};
const vwc = Number(p.vwc);
const vwcFcRef = Number(p.vwcFcRef ?? p.field_capacity_estimate ?? p.field_capacity ?? 0);
const vwcLowRef = Number(p.vwcLowRef ?? p.paw_low_ref ?? p.vwc_floor_ref ?? 0);

let pawPct = null;
let totalRangePct = null;
let availablePct = null;

if (Number.isFinite(vwc) && Number.isFinite(vwcFcRef) && vwcFcRef > 0 && Number.isFinite(vwcLowRef) && vwcLowRef >= 0) {
  totalRangePct = Math.max(0, vwcFcRef - vwcLowRef);
  availablePct = Math.max(0, vwc - vwcLowRef);
  pawPct = totalRangePct > 0 ? Math.max(0, Math.min(100, (availablePct / totalRangePct) * 100)) : null;
}

msg.payload = {
  ...p,
  pawPct,
  availablePct,
  totalRangePct,
  vwcFcRef,
  vwcLowRef,
  pawLabel: pawPct == null ? 'n/a' : `${pawPct.toFixed(1)} %`,
  pawStatus: pawPct == null ? 'missing_inputs' : 'ok'
};

return msg;
